    int q{};
    std::cin >> va >> vb >> q;

    // Start each resource in a unique_ptr, then move it into a shared_ptr.
    // Keep reader copies in a container and process q commands:
    //   holdA / holdB -> push a copy of A / B
    //   drop          -> pop the last reader
    //   report        -> print "A=<A.use_count()> B=<B.use_count()>"
    //   read          -> print "sum=<sum of *reader over all readers>"

    return 0;
}

solution_code:
#include <iostream>
#include <memory>
#include <string>
#include <vector>
int main(){
    int va{}, vb{}, q{};
    std::cin >> va >> vb >> q;
    auto ua = std::make_unique<int>(va);
    std::shared_ptr<int> A{ std::move(ua) };
    auto ub = std::make_unique<int>(vb);
    std::shared_ptr<int> B{ std::move(ub) };
    std::vector<std::shared_ptr<int>> holders;
    for(int i=0;i<q;++i){
        std::string cmd; std::cin >> cmd;
        if(cmd=="holdA") holders.push_back(A);
        else if(cmd=="holdB") holders.push_back(B);
        else if(cmd=="drop"){ if(!holders.empty()) holders.pop_back(); }
        else if(cmd=="report") std::cout << "A=" << A.use_count() << " B=" << B.use_count() << '\n';
        else if(cmd=="read"){ int sum=0; for(const auto& p:holders) sum+=*p; std::cout << "sum=" << sum << '\n'; }
    }
    return 0;
}
